SET FOREIGN_KEY_CHECKS = 1;

-- 1. 점주 계정이 200명인지 확인
SELECT COUNT(*) FROM member WHERE member_role_type = 'OWNER';

-- 2. 가게가 200개인지 확인
SELECT COUNT(*) FROM store;

-- 3. 카테고리별로 40개씩 잘 들어갔는지 확인
SELECT store_category, COUNT(*) FROM store GROUP BY store_category;

-- 4. 메뉴가 가게마다 잘 연결됐는지 샘플 확인
SELECT s.store_name, m.menu_name, m.menu_price 
FROM store s 
JOIN store_menu m ON s.store_idx = m.store_idx 
LIMIT 10;